To convert Markdown to HTML, you can use a library like **cpp markdown**. However, for simplicity and to demonstrate the process, I'll write a function that converts a simple subset of Markdown to HTML. This function will handle the following Markdown elements:

- Bold text: `**text**` to `<strong>text</strong>`
- Italic text: `*text*` to `<em>text</em>`
- Headers: `# text` to `<h1>text</h1>`
- Unordered lists: `- item` to `<li>item</li>`

Here is how you can implement such a function:

```cpp
#include <string>
#include <vector>
#include <iostream>
#include <sstream>
#include <cassert>

std::string markdown_to_html(const std::string& markdown) {
    std::string html;
    std::istringstream iss(markdown);
    std::string line;

    while (std::getline(iss, line)) {
        // Headers
        if (line[0] == '#') {
            html += "<h1>" + line.substr(2) + "</h1>";
        } else {
            size_t pos = 0;
            while ((pos = line.find("**", pos)) != std::string::npos) {
                // Bold text
                html += line.substr(0, pos) + "<strong>";
                pos += 2;
                size_t end_pos = line.find("**", pos);
                if (end_pos != std::string::npos) {
                    html += line.substr(pos, end_pos - pos) + "</strong>";
                    pos = end_pos + 2;
                }
            }
            pos = 0;
            while ((pos = line.find("*", pos)) != std::string::npos) {
                // Italic text
                if (pos > 0 && line[pos - 1] != '*' && line[pos + 1] != '*') {
                    html += line.substr(0, pos) + "<em>";
                    pos++;
                    size_t end_pos = line.find("*", pos);
                    if (end_pos != std::string::npos) {
                        html += line.substr(pos, end_pos - pos) + "</em>";
                        pos = end_pos + 1;
                    }
                } else {
                    pos++;
                }
            }
            // Unordered lists
            if (line[0] == '-') {
                html += "<li>" + line.substr(2) + "</li>";
            } else {
                html += line;
            }
        }
        html += "\n";
    }
    return html;
}

void check_conversion(const std::string& markdown, const std::string& expected_html) {
    std::string result = markdown_to_html(markdown);
    assert(result == expected_html);
}

int main() {
    // Test cases
    check_conversion("# Hello, *world*!\n**This is bold.**\n- List item", "<h1>Hello, <em>world</em>!</h1><strong>This is bold.</strong><li>List item</li>\n");
    check_conversion("*Italic* and **bold**", "<em>Italic</em> and <strong>bold</strong>\n");
    check_conversion("# Header\n- Item1\n- Item2", "<h1>Header</h1><li>Item1</li><li>Item2</li>\n");

    std::cout << "All tests passed." << std::endl;
    return 0;
}
```

This function is quite basic and does not handle all Markdown features, nor does it handle edge cases or complex Markdown syntax. For a more complete solution, you should consider using a well-tested library rather than writing your own parser.

