function isPrime(num) {
  if (num <= 1) return false;
  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) return false;
  }
  return true;
}

function printPrimeNumbers(arr) {
  if (arr.length !== 5) {
    console.log("Error: Array must contain exactly 5 numbers.");
    return;
  }

  for (let i = 0; i < arr.length; i++) {
    if (isPrime(arr[i])) {
      console.log(arr[i]);
    }
  }
}

// Test the function with an array of 5 numbers
