    .modal-content {
      background-color: #fefefe;
      margin: auto;
      padding: 20px;
      border: 1px solid #888;
      width: 80%;
    }

    /* The Close Button */
    .close {
      color: #aaaaaa;
      float: right;
      font-size: 28px;
      font-weight: bold;
    }

    .close:hover,
    .close:focus {
      color: #000;
      text-decoration: none;
      cursor: pointer;
    }

    /* Style for chat messages */
    .chat-message {
      padding: 10px;
      border-radius: 5px;
      margin-bottom: 10px;
    }

    /* Style for bot messages */
    .bot-message {
      background-color: #007bff;
      color: white;
      float: left;
      clear: both;
    }

    /* Style for human messages */
    .human-message {
      background-color: #f4f4f4;
      color: black;
      float: right;
    }
  </style>
</head>
<body>

<!-- Trigger/Open The Modal -->
